// Lead Scoring Logic
const lead = $input.first().json;
let score = 0;
const reasons = [];

// Industry scoring
const industryScores = {
  food: 25,
  legal: 30,
  medical: 35,
  other: 15
};
if (lead.industry) {
  score += industryScores[lead.industry] || 15;
  reasons.push(`${lead.industry} industry (+${industryScores[lead.industry] || 15})`);
}

// Fleet size scoring
const fleetScores = {
  solo: 10,
  business: 25,
  enterprise: 40
};
if (lead.fleet_size) {
  score += fleetScores[lead.fleet_size] || 10;
  reasons.push(`${lead.fleet_size} fleet size (+${fleetScores[lead.fleet_size] || 10})`);
}

// Message quality (has specific use case)
if (lead.message && lead.message.length > 20) {
  score += 15;
  reasons.push('Detailed use case provided (+15)');
}

// Phone provided (higher intent than email-only)
if (lead.phone && lead.phone.length > 9) {
  score += 10;
  reasons.push('Phone provided (+10)');
}

// Business name provided
if (lead.business_name && lead.business_name.length > 2) {
  score += 5;
  reasons.push('Business name provided (+5)');
}

// Determine tier
let tier = 'cold';
if (score >= 70) tier = 'hot';
else if (score >= 50) tier = 'warm';
else if (score >= 30) tier = 'mild';

// Determine recommended product
let recommendedProduct = 'SAOS Solo Agent';
if (lead.fleet_size === 'business') recommendedProduct = 'SAOS Business Fleet';
if (lead.fleet_size === 'enterprise') recommendedProduct = 'SAOS Enterprise Fleet';
if (lead.industry === 'medical' || lead.industry === 'legal') recommendedProduct = 'SAOS Business Fleet';

return [{
  json: {
    ...lead,
    lead_score: score,
    lead_tier: tier,
    score_reasons: reasons,
    recommended_product: recommendedProduct,
    source: 'SAOS Website Lead Form',
    submitted_at: new Date().toISOString(),
    status: 'new'
  }
}];

// Insert lead into CRM database using sqlite3
// n8n v2 Code Node: resolve reference strings by walking the input item
const sqlite3 = require('sqlite3');
const item = $input.first();
const rawLead = item.json;

// n8n reference strings appear as numeric strings pointing to other items.
// If lead.name is a reference, the data may be nested under lead.body
// or elsewhere. Resolve by checking typeof and falling back to body.
function resolve(val) {
  if (typeof val === 'string' && /^\d+$/.test(val)) {
    return undefined;  // reference string, treat as missing so we fall back
  }
  return val;
}

const lead = {};
const keys = Object.keys(rawLead);
for (const k of keys) {
  lead[k] = rawLead[k];
}

// If name is a reference string, attempt to read from body
let name = resolve(lead.name);
let business_name = resolve(lead.business_name);
let email = resolve(lead.email);
let phone = resolve(lead.phone);
let industry = resolve(lead.industry);
let fleet_size = resolve(lead.fleet_size);
let message = resolve(lead.message);

if (lead.body && typeof lead.body === 'object') {
  const b = lead.body;
  if (name === undefined) name = resolve(b.name);
  if (business_name === undefined) business_name = resolve(b.business_name);
  if (email === undefined) email = resolve(b.email);
  if (phone === undefined) phone = resolve(b.phone);
  if (industry === undefined) industry = resolve(b.industry);
  if (fleet_size === undefined) fleet_size = resolve(b.fleet_size);
  if (message === undefined) message = resolve(b.message);
}

console.log('CRM node resolved lead:', { name, business_name, email, phone, industry, fleet_size, message });

const dbPath = '/Users/philliplowe/.openclaw/workspaces/sol/green-systems-crm.db';

return new Promise((resolve, reject) => {
  const db = new sqlite3.Database(dbPath, (err) => {
    if (err) {
      resolve([{
        json: {
          ...lead,
          _resolved: { name, business_name, email, phone, industry, fleet_size, message },
          db_error: err.message,
          db_status: 'connection_failed'
        }
      }]);
      return;
    }

    const query = `INSERT INTO leads (
      name, address, phone, email, category, score, stage, owner, 
      created_date, source, notes
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`;

    const values = [
      name || business_name || 'Unknown',
      business_name || '',
      phone || '',
      email || '',
      industry || 'other',
      lead.lead_score || 0,
      lead.lead_tier || 'cold',
      'Green',
      new Date().toISOString(),
      'saos_web_form',
      `Fleet size: ${fleet_size || 'unknown'}. Message: ${message || 'N/A'}`
    ];

    db.run(query, values, function(err) {
      if (err) {
        db.close();
        resolve([{
          json: {
            ...lead,
            _resolved: { name, business_name, email, phone, industry, fleet_size, message },
            db_error: err.message,
            db_status: 'insert_failed'
          }
        }]);
        return;
      }
      const lastId = this.lastID;
      db.close();
      resolve([{
        json: {
          ...lead,
          _resolved: { name, business_name, email, phone, industry, fleet_size, message },
          db_status: 'success',
          db_id: lastId,
          db_message: 'Lead saved to CRM'
        }
      }]);
    });
  });
});
